// ================================
// CREATE PACKAGE CARDS
// ================================
var packageNames = [
  "Kedarnath",
  "Ooty",
  "Madhya Pradesh",
  "Singapore",
  "Dubai"
];

var container = document.getElementById("package-list");

for (var i = 0; i < packageNames.length; i++) {
  var pkg = packageNames[i];
  var data = itineraries[pkg];

  var card = document.createElement("div");
  card.className = "package-card";

  card.innerHTML = `
    <h3>${pkg}</h3>
    <p><strong>Available Dates:</strong> ${data.dates.join(", ")}</p>
    <p><strong>Cost:</strong> ₹${data.price} / person</p>
    <p><strong>Total Seats:</strong> ${data.totalSeats}</p>
  `;

  var btn = document.createElement("button");
  btn.innerText = "View Itinerary & Book Here";

  btn.onclick = (function (pkgName) {
    return function () {
      openPackage(pkgName);
    };
  })(pkg);

  card.appendChild(btn);
  container.appendChild(card);
}

// ================================
// OPEN PACKAGE (ITINERARY + BOOKING)
// ================================
var selectedPackageName = ""; // Global variable to store package name

function openPackage(packageName) {

  selectedPackageName = packageName; // store selected package

  document.getElementById("itinerarySection").innerHTML = "";
  document.getElementById("bookingSection").innerHTML = "";

  var data = itineraries[packageName];

  // build itinerary HTML
  let itineraryHTML = `
    <h2>${packageName} – Itinerary</h2>
    <img src="${data.image}" class="itinerary-image">
    <ul>
  `;

  data.days.forEach(day => {
    itineraryHTML += `<li>${day}</li>`;
  });

  itineraryHTML += `</ul>`;
  document.getElementById("itinerarySection").innerHTML = itineraryHTML;


  // create travel date dropdown
  let dateOptions = "";
  data.dates.forEach(date => {
    dateOptions += `<option value="${date}">${date}</option>`;
  });


  // render booking form
  document.getElementById("bookingSection").innerHTML = `
    <h2>Book ${packageName} Package</h2>

    <form id="bookingForm">

      <input type="text" id="pkgName" placeholder="Full Name" required>
      <input type="number" id="pkgAge" placeholder="Age" required>
      <input type="text" id="pkgAddress" placeholder="Home Address" required>
      <input type="tel" id="pkgMobile" placeholder="Mobile Number" required>
      <input type="email" id="pkgEmail" placeholder="Email Address" required>

      <input type="number" id="travelers" placeholder="Number of travelers">

      <textarea id="pkgMessage" placeholder="Any request or notes?"></textarea>

      <select id="pkgTravelDate" required>
        <option value="">Select Travel Date</option>
        ${dateOptions}
      </select>

      <input type="hidden" id="destination">

      <button type="submit" class="btn">Confirm Booking</button>

    </form>
  `;


  // set destination auto value
  document.getElementById("destination").value = packageName;

  // attach event listener after DOM updates
  setTimeout(() => {
    document.getElementById("bookingForm")
      .addEventListener("submit", confirmBooking);
  }, 0);

}



// ================================
// CONFIRM BOOKING
// ================================
function confirmBooking(event) {
  event.preventDefault();

  const name = document.getElementById("pkgName").value;
  const age = document.getElementById("pkgAge").value;
  const address = document.getElementById("pkgAddress").value;
  const mobile = document.getElementById("pkgMobile").value;
  const email = document.getElementById("pkgEmail").value;
  const travelDate = document.getElementById("pkgTravelDate").value;

  const destination = document.getElementById("destination").value;
  const people = document.getElementById("travelers").value;
  const message = document.getElementById("pkgMessage").value;

  // ===== BASIC REQUIRED CHECK =====
  if (!name || !age || !mobile || !email) {
    alert("Please fill all details before booking.");
    return;
  }

  // ===== AGE VALIDATION =====
  if (age < 18) {
    alert("Minimum age should be 18 to book.");
    return;
  }

  // ===== MOBILE VALIDATION (9 digits only) =====
  if (mobile.length !== 9 || isNaN(mobile)) {
    alert("Mobile number must be exactly 9 digits.");
    return;
  }

  // ===== EMAIL VALIDATION (@ and . required) =====
  if (email.indexOf("@") === -1 || email.indexOf(".") === -1) {
    alert("Please enter a valid email address (example: name@gmail.com).");
    return;
  }

  // ===== SAVE TO LOCAL STORAGE =====
  let trips = JSON.parse(localStorage.getItem("trips")) || [];

  trips.push({
    formType: "Package Booking",
    name,
    age,
    address,
    mobile,
    email,
    travelDate,
    destination,
    people,
    message,
    createdAt: new Date().toLocaleString()
  });

  localStorage.setItem("trips", JSON.stringify(trips));

  alert(
    "Booking confirmed and saved 😊\n\n" +
    "Our employee will come for in-person verification at your place."
  );
}
